#!/usr/bin/env python3
"""
Dependency Lock File Management (requirements.txt with hashes and Poetry locks)

This script is both runnable and serves as internal documentation for dependency
management best practices. It supports two workflows:

  1) pip-tools (requirements.in -> requirements.txt with hashes)
  2) Poetry (pyproject.toml -> poetry.lock)

Goal:
  - Consistent, repeatable dependency versions across dev/prod/CI.
  - Lock files committed to VCS.
  - Deterministic installs via hashes (pip) or lock resolution (Poetry).

===============================================================================
A) pip-tools workflow (recommended if using requirements*.txt)
===============================================================================

Files:
  - requirements.in        (top-level, human-edited direct deps only)
  - requirements-dev.in    (dev/test tooling, optionally includes -r requirements.in)
  - requirements.txt       (generated lock with pinned versions + hashes)
  - requirements-dev.txt   (generated lock for dev deps + hashes)

Rules:
  - Edit *.in files only.
  - Never manually edit the generated *.txt lock files.
  - Commit both *.in and generated *.txt files.

Example requirements.in:
  fastapi>=0.110
  uvicorn[standard]>=0.27
  pydantic>=2.6

Example requirements-dev.in:
  -r requirements.in
  pytest>=8
  ruff>=0.4

Generate/Update:
  - "compile" resolves versions and writes the lock file with hashes.
  - "upgrade" updates versions to newest allowed by your constraints.
  - "sync" installs exactly what is locked (including removals).

Recommended practices:
  - Use Python version constraints in your project documentation and CI.
  - Use the same base image/runtime in production that dev/CI uses (or close).
  - Keep direct dependency specs broad (>=) and let the lock pin exactly.
  - Review diffs of lock files in PRs.

===============================================================================
B) Poetry workflow (recommended if using pyproject.toml)
===============================================================================

Files:
  - pyproject.toml     (human-edited direct deps and constraints)
  - poetry.lock        (generated lock, exact versions + metadata)

Rules:
  - Edit pyproject.toml only.
  - Never manually edit poetry.lock.
  - Commit both.

Generate/Update:
  - "lock" creates/refreshes lock without changing constraints.
  - "update" updates dependencies to latest allowed by constraints.

Install:
  - Use "poetry install" which honors poetry.lock.
  - For CI/prod, disable dev dependencies as needed.

===============================================================================
Usage
===============================================================================

This script provides a unified interface and preflight checks.

Examples (pip-tools):
  python tools/deps.py pip compile
  python tools/deps.py pip compile --dev
  python tools/deps.py pip upgrade
  python tools/deps.py pip sync --dev
  python tools/deps.py pip verify

Examples (poetry):
  python tools/deps.py poetry lock
  python tools/deps.py poetry update
  python tools/deps.py poetry install
  python tools/deps.py poetry verify

Exit codes:
  0 success
  non-zero on errors

Notes:
  - This script invokes external tools (pip-compile, pip-sync, poetry).
  - Install tool prerequisites:
      pip install pip-tools
      pip install poetry  (or via official installer)

"""

from __future__ import annotations

import argparse
import os
import re
import shutil
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, Sequence


@dataclass(frozen=True)
class RunResult:
    returncode: int


def eprint(*args: object) -> None:
    print(*args, file=sys.stderr)


def run(cmd: Sequence[str], cwd: Path | None = None, env: dict[str, str] | None = None) -> RunResult:
    eprint("+", " ".join(cmd))
    p = subprocess.run(list(cmd), cwd=str(cwd) if cwd else None, env=env)
    return RunResult(p.returncode)


def which(name: str) -> str | None:
    return shutil.which(name)


def require_tool(tool: str, hint: str | None = None) -> None:
    if which(tool) is None:
        msg = f"Required tool not found on PATH: {tool}"
        if hint:
            msg += f"\nHint: {hint}"
        raise SystemExit(msg)


def project_root(start: Path | None = None) -> Path:
    here = (start or Path.cwd()).resolve()
    for p in [here, *here.parents]:
        if (p / ".git").exists() or (p / "pyproject.toml").exists() or (p / "requirements.in").exists():
            return p
    return here


def read_text_if_exists(path: Path) -> str:
    try:
        return path.read_text(encoding="utf-8")
    except FileNotFoundError:
        return ""


def pip_compile_args(
    input_file: Path,
    output_file: Path,
    *,
    upgrade: bool,
    python_executable: str | None,
    extra_args: list[str] | None = None,
) -> list[str]:
    args = ["pip-compile"]
    args += ["--generate-hashes"]
    args += ["--allow-unsafe"]
    args += ["--resolver=backtracking"]
    args += ["--output-file", str(output_file)]
    if upgrade:
        args += ["--upgrade"]
    if python_executable:
        args += ["--python-executable", python_executable]
    if extra_args:
        args += extra_args
    args += [str(input_file)]
    return args


def pip_sync_args(lock_files: list[Path]) -> list[str]:
    args = ["pip-sync"]
    args += [str(p) for p in lock_files]
    return args


def default_pip_files(root: Path, dev: bool) -> tuple[Path, Path]:
    if dev:
        return root / "requirements-dev.in", root / "requirements-dev.txt"
    return root / "requirements.in", root / "requirements.txt"


def validate_pip_inputs(root: Path, dev: bool) -> None:
    in_file, out_file = default_pip_files(root, dev)
    if not in_file.exists():
        raise SystemExit(f"Missing {in_file.name}. Create it with top-level dependencies.")
    if out_file.exists():
        txt = read_text_if_exists(out_file)
        if "Generated by pip-compile" not in txt:
            eprint(f"Warning: {out_file.name} exists but does not look like a pip-compile output.")


def verify_requirements_hashes(lock_file: Path) -> None:
    txt = read_text_if_exists(lock_file)
    if not txt:
        raise SystemExit(f"Lock file not found or empty: {lock_file}")
    bad = []
    for line in txt.splitlines():
        s = line.strip()
        if not s or s.startswith("#") or s.startswith("-r") or s.startswith("--"):
            continue
        if s.startswith(("git+", "hg+", "svn+", "bzr+")):
            continue
        if ";" in s:
            pkg_part = s.split(";", 1)[0].strip()
        else:
            pkg_part = s
        if "==" in pkg_part and "--hash=" not in s:
            bad.append(line)
    if bad:
        raise SystemExit(
            "Lock file appears to be missing hashes for some pinned requirements.\n"
            f"File: {lock_file}\n"
            "Examples:\n  - " + "\n  - ".join(bad[:10]) + ("\n  ..." if len(bad) > 10 else "")
        )


def detect_poetry_project(root: Path) -> bool:
    return (root / "pyproject.toml").exists()


def verify_poetry_lock(root: Path) -> None:
    lock_path = root / "poetry.lock"
    if not lock_path.exists():
        raise SystemExit("poetry.lock not found. Run: poetry lock")
    pyproject = root / "pyproject.toml"
    if not pyproject.exists():
        raise SystemExit("pyproject.toml not found.")

    # Basic check: lock must contain a metadata section and at least one package.
    txt = read_text_if_exists(lock_path)
    if "[[package]]" not in txt or "[metadata]" not in txt:
        raise SystemExit("poetry.lock does not look valid (missing package/metadata sections).")

    # Basic check: Poetry version markers sometimes present; do not hard fail.
    # Ensure it's not empty.
    if len(txt.strip()) < 100:
        raise SystemExit("poetry.lock seems unexpectedly small; verify lock generation.")


def check_constraints_alignment(root: Path) -> None:
    pyproject = root / "pyproject.toml"
    if pyproject.exists():
        txt = read_text_if_exists(pyproject)
        m = re.search(r'^\s*python\s*=\s*"([^"]+)"\s*$', txt, flags=re.MULTILINE)
        if m:
            eprint(f"Note: pyproject.toml python constraint: {m.group(1)}")
    req_in = root / "requirements.in"
    if req_in.exists():
        eprint("Note: requirements.in present. Ensure your runtime Python version is fixed in tooling/CI.")


def cmd_pip_compile(root: Path, dev: bool, upgrade: bool, python_executable: str | None, extra: list[str]) -> int:
    require_tool("pip-compile", "pip install pip-tools")
    validate_pip_inputs(root, dev)

    in_file, out_file = default_pip_files(root, dev)

    args = pip_compile_args(
        in_file,
        out_file,
        upgrade=upgrade,
        python_executable=python_executable,
        extra_args=extra or None,
    )
    rc = run(args, cwd=root).returncode
    if rc != 0:
        return rc

    verify_requirements_hashes(out_file)
    eprint(f"OK: generated {out_file.relative_to(root)}")
    return 0


def cmd_pip_upgrade(root: Path, dev: bool, python_executable: str | None, extra: list[str]) -> int:
    return cmd_pip_compile(root, dev=dev, upgrade=True, python_executable=python_executable, extra=extra)


def cmd_pip_sync(root: Path, dev: bool) -> int:
    require_tool("pip-sync", "pip install pip-tools")

    lock_files: list[Path] = []
    base_lock = root / "requirements.txt"
    dev_lock = root / "requirements-dev.txt"
    if not base_lock.exists():
        raise SystemExit("requirements.txt not found. Run: deps.py pip compile")
    lock_files.append(base_lock)
    if dev:
        if not dev_lock.exists():
            raise SystemExit("requirements-dev.txt not found. Run: deps.py pip compile --dev")
        lock_files.append(dev_lock)

    for lf in lock_files:
        verify_requirements_hashes(lf)

    rc = run(pip_sync_args(lock_files), cwd=root).returncode
    if rc == 0:
        eprint("OK: environment synced to lock files")
    return rc


def cmd_pip_verify(root: Path, dev: bool) -> int:
    base_lock = root / "requirements.txt"
    dev_lock = root / "requirements-dev.txt"

    if not base_lock.exists():
        raise SystemExit("requirements.txt not found.")
    verify_requirements_hashes(base_lock)

    if dev:
        if not dev_lock.exists():
            raise SystemExit("requirements-dev.txt not found.")
        verify_requirements_hashes(dev_lock)

    eprint("OK: pip lock files look consistent (pinned + hashed).")
    return 0


def cmd_poetry_lock(root: Path, no_update: bool) -> int:
    require_tool("poetry", "Install Poetry (https://python-poetry.org/docs/#installation)")
    if not detect_poetry_project(root):
        raise SystemExit("pyproject.toml not found. Not a Poetry project?")
    args = ["poetry", "lock"]
    if no_update:
        args.append("--no-update")
    rc = run(args, cwd=root).returncode
    if rc != 0:
        return rc
    verify_poetry_lock(root)
    eprint("OK: poetry.lock present and looks valid.")
    return 0


def cmd_poetry_update(root: Path) -> int:
    require_tool("poetry", "Install Poetry (https://python-poetry.org/docs/#installation)")
    if not detect_poetry_project(root):
        raise SystemExit("pyproject.toml not found. Not a Poetry project?")
    rc = run(["poetry", "update"], cwd=root).returncode
    if rc != 0:
        return rc
    verify_poetry_lock(root)
    eprint("OK: updated poetry.lock.")
    return 0


def cmd_poetry_install(root: Path, with_dev: bool) -> int:
    require_tool("poetry", "Install Poetry (https://python-poetry.org/docs/#installation)")
    if not detect_poetry_project(root):
        raise SystemExit("pyproject.toml not found. Not a Poetry project?")
    args = ["poetry", "install"]
    if not with_dev:
        args += ["--only", "main"]
    rc = run(args, cwd=root).returncode
    return rc


def cmd_poetry_verify(root: Path) -> int:
    require_tool("poetry", "Install Poetry (https://python-poetry.org/docs/#installation)")
    verify_poetry_lock(root)
    rc = run(["poetry", "check"], cwd=root).returncode
    if rc != 0:
        return rc
    eprint("OK: Poetry project checks passed and lock exists.")
    return 0


def build_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(
        prog="deps.py",
        description="Manage dependency lock files (pip-tools or Poetry) for consistent dev/prod builds.",
    )
    p.add_argument("--root", default=None, help="Project root (default: auto-detect).")

    sub = p.add_subparsers(dest="tool", required=True)

    pip_p = sub.add_parser("pip", help="pip-tools workflow: requirements.in -> requirements.txt (hashed)")
    pip_sub = pip_p.add_subparsers(dest="action", required=True)

    pip_compile = pip_sub.add_parser("compile", help="Generate lock file(s) from *.in")
    pip_compile.add_argument("--dev", action="store_true", help="Compile dev lock (requirements-dev.*)")
    pip_compile.add_argument("--python-executable", default=None, help="Python executable to resolve against")
    pip_compile.add_argument("--extra", action="append", default=[], help="Extra args to pass to pip-compile")
    pip_compile.set_defaults(_fn=lambda a, r: cmd_pip_compile(r, a.dev, False, a.python_executable, a.extra))

    pip_upgrade = pip_sub.add_parser("upgrade", help="Upgrade dependencies within constraints and regenerate lock")
    pip_upgrade.add_argument("--dev", action="store_true", help="Upgrade dev lock (requirements-dev.*)")
    pip_upgrade.add_argument("--python-executable", default=None, help="Python executable to resolve against")
    pip_upgrade.add_argument("--extra", action="append", default=[], help="Extra args to pass to pip-compile")
    pip_upgrade.set_defaults(_fn=lambda a, r: cmd_pip_upgrade(r, a.dev, a.python_executable, a.extra))

    pip_sync = pip_sub.add_parser("sync", help="Sync installed packages to match lock file(s) exactly")
    pip_sync.add_argument("--dev", action="store_true", help="Include dev lock in sync")
    pip_sync.set_defaults(_fn=lambda a, r: cmd_pip_sync(r, a.dev))

    pip_verify = pip_sub.add_parser("verify", help="Verify lock files exist and contain hashes for pinned deps")
    pip_verify.add_argument("--dev", action="store_true", help="Verify dev lock as well")
    pip_verify.set_defaults(_fn=lambda a, r: cmd_pip_verify(r, a.dev))

    poetry_p = sub.add_parser("poetry", help="Poetry workflow: pyproject.toml -> poetry.lock")
    poetry_sub = poetry_p.add_subparsers(dest="action", required=True)

    poetry_lock = poetry_sub.add_parser("lock", help="Generate/refresh poetry.lock")
    poetry_lock.add_argument("--no-update", action="store_true", help="Do not update versions, just refresh lock")
    poetry_lock.set_defaults(_fn=lambda a, r: cmd_poetry_lock(r, a.no_update))

    poetry_update = poetry_sub.add_parser("update", help="Update dependencies within constraints and refresh lock")
    poetry_update.set_defaults(_fn=lambda a, r: cmd_poetry_update(r))

    poetry_install = poetry_sub.add_parser("install", help="Install dependencies from poetry.lock")
    poetry_install.add_argument("--with-dev", action="store_true", help="Include dev dependencies")
    poetry_install.set_defaults(_fn=lambda a, r: cmd_poetry_install(r, a.with_dev))

    poetry_verify = poetry_sub.add_parser("verify", help="Verify poetry.lock exists and project checks pass")
    poetry_verify.set_defaults(_fn=lambda a, r: cmd_poetry_verify(r))

    return p


def main(argv: Sequence[str] | None = None) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)

    root = project_root(Path(args.root).resolve() if args.root else None)
    os.environ.setdefault("PIP_DISABLE_PIP_VERSION_CHECK", "1")
    check_constraints_alignment(root)

    fn = getattr(args, "_fn", None)
    if not fn:
        parser.error("No action selected.")
    try:
        return int(fn(args, root))
    except KeyboardInterrupt:
        eprint("Interrupted.")
        return 130


if __name__ == "__main__":
    raise SystemExit(main())